mapper.select:
select

from flow_his_task fht
inner join flow_his_instance fhi on fht.instance_id = fhi.id and fhi.deleted = 0
inner join flow_model fm on fht.model_id = fm.id and fm.deleted = 0
where fht.deleted = 0

    and fht.instance_id = #{ew.instanceId}


    and fht.name like concat('%', #{ew.taskName}, '%')


    and fhi.name like concat('%', #{ew.instanceName}, '%')


    and fhi.biz_number = #{ew.bizNumber}


    and fht.status = #{ew.status}


    and exists (
        select 1 from flow_his_task_player fhtp
        where fhtp.task_id = fht.id and fhtp.deleted = 0 and fhtp.player_id = #{ew.userId}
    )

order by fht.modified_time desc
